// // This module implements a positive-edge-triggered D flip-flop with active low clock enable (CE). The flip-flop captures the input data (D) on the rising edge of the clock (CLK) only when the clock enable is deasserted.
module top_module(output reg Q, input D, CLK, CE);parameter [0:0] INIT = 1'b0; 
  initial Q = INIT; 
  always @(negedge CLK) begin 
  if (CE) 
  Q <= D; 
  end 
 endmodule
